class IntQueue {
  private static class Node {
    int value;
    Node next;

    Node(int value) {
      this.value = value;
    }
  }

  private Node front;
  private Node rear;

  void enqueue(int value) {
    Node node = new Node(value);
    if (rear != null) {
      rear.next = node;
    }
    rear = node;
    if (front == null) {
      front = rear;
    }
  }

  int dequeue() {
    if (front == null) {
      throw new IllegalStateException("underflow");
    }
    int value = front.value;
    front = front.next;
    if (front == null) {
      rear = null;
    }
    return value;
  }
}
